    const sumsCount = new Map();

    // Calculate the maximum possible value for b. 
    // Since a >= 1, b^3 < n.
    const maxB = Math.floor(Math.cbrt(n));

    for (let b = 1; b <= maxB; b++) {
        // Pre-calculate b^3. Using multiplication to avoid potential floating point issues with cbrt on large numbers, 
        // although for n <= 10^9, standard calculation is safe.
        const b3 = b * b * b;

        // Determine the maximum possible value for a, constrained by a <= b and a^3 + b^3 <= n.
        const remaining = n - b3;

        if (remaining < 1) {
            // This check handles cases where b itself might be too large if maxB was slightly overestimated due to floating point math,
            // though mathematically it should not happen if maxB is correctly floored.
            continue; 
        }

        // maxA based on the sum constraint: a^3 <= remaining
        const maxA_sum = Math.floor(Math.cbrt(remaining));

        // Actual max A must satisfy both a <= b and a <= maxA_sum
        const actualMaxA = Math.min(b, maxA_sum);

        for (let a = 1; a <= actualMaxA; a++) {
            const a3 = a * a * a;
            const x = a3 + b3;

            // Since we used maxA_sum, x <= n is guaranteed, but we ensure the key exists in the map.

            // Update count
            const currentCount = sumsCount.get(x) || 0;
            sumsCount.set(x, currentCount + 1);
        }
    }

    // Collect all sums that appeared at least twice (good integers)
    const goodIntegers = [];
    for (const [sum, count] of sumsCount.entries()) {
        if (count >= 2) {
            // Since n <= 10^9, the sum fits safely as a standard JS Number.
            goodIntegers.push(sum);
        }
    }

    // Return the results sorted in ascending order
    goodIntegers.sort((a, b) => a - b);

    return goodIntegers;
}

